1	/**
2	 * IndexedDB wrapper for HarborGate data.
3	 * Supports encryption at rest for sensitive stores via a session-derived CryptoKey.
4	 */
5	const DB_NAME = 'harborgate';
6	const DB_VERSION = 2;
7	
8	// Stores whose records are encrypted at rest when a session key is available.
9	// NOTE: 'users' and 'roles' are intentionally excluded — user records must be
10	// readable pre-auth (before any session key exists) so that login can read
11	// passwordHash/salt for verification. Auth fields are already protected by
12	// PBKDF2 hashing; encrypting them with a per-session key would lock users out
13	// whenever an admin updates their record under a different key.
14	const ENCRYPTED_STORES = new Set([
15	  'reservations',
16	  'entry_permissions',
17	  'devices',
18	  'pois',
19	  'content',
20	  'reports',
21	  'audit_logs',
22	  'notifications',
23	  'command_outbox',
24	  'rate_limits',
25	  'zones',
26	  'geofences'
27	]);
28	
29	const STORES = {
30	  users: { keyPath: 'id', autoIncrement: true, indexes: [{ name: 'username', keyPath: 'username', unique: true }, { name: 'role', keyPath: 'role' }] },
31	  roles: { keyPath: 'id', autoIncrement: true, indexes: [{ name: 'name', keyPath: 'name', unique: true }] },
32	  rate_limits: { keyPath: 'id', autoIncrement: true, indexes: [{ name: 'scope', keyPath: 'scope' }, { name: 'action', keyPath: 'action' }] },
33	  reservations: { keyPath: 'id', autoIncrement: true, indexes: [{ name: 'userId', keyPath: 'userId' }, { name: 'status', keyPath: 'status' }] },
34	  entry_permissions: { keyPath: 'id', autoIncrement: true, indexes: [{ name: 'reservationId', keyPath: 'reservationId' }, { name: 'status', keyPath: 'status' }] },
35	  devices: { keyPath: 'id', autoIncrement: true, indexes: [{ name: 'zone', keyPath: 'zone' }, { name: 'status', keyPath: 'status' }] },
36	  pois: { keyPath: 'id', autoIncrement: true, indexes: [{ name: 'zone', keyPath: 'zone' }] },
37	  content: { keyPath: 'id', autoIncrement: true, indexes: [{ name: 'status', keyPath: 'status' }, { name: 'workflowState', keyPath: 'workflowState' }] },
38	  reports: { keyPath: 'id', autoIncrement: true, indexes: [{ name: 'type', keyPath: 'type' }, { name: 'status', keyPath: 'status' }] },
39	  audit_logs: { keyPath: 'id', autoIncrement: true, indexes: [{ name: 'actor', keyPath: 'actor' }, { name: 'timestamp', keyPath: 'timestamp' }, { name: 'action', keyPath: 'action' }] },
40	  notifications: { keyPath: 'id', autoIncrement: true, indexes: [{ name: 'userId', keyPath: 'userId' }, { name: 'read', keyPath: 'read' }, { name: 'scheduledFor', keyPath: 'scheduledFor' }] },
41	  command_outbox: { keyPath: 'id', autoIncrement: true, indexes: [{ name: 'status', keyPath: 'status' }, { name: 'deviceId', keyPath: 'deviceId' }] },
42	  zones: { keyPath: 'id', autoIncrement: true },
43	  geofences: { keyPath: 'id', autoIncrement: true, indexes: [{ name: 'zone', keyPath: 'zone' }] }
44	};
45	
46	let dbInstance = null;
47	
48	// In-memory encryption key — never persisted
49	let _encryptionKey = null;
50	
51	function setEncryptionKey(key) {
52	  _encryptionKey = key;
53	}
54	
55	function clearEncryptionKey() {
56	  _encryptionKey = null;
57	}
58	
59	function getEncryptionKey() {
60	  return _encryptionKey;
61	}
62	
63	async function encryptIfNeeded(storeName, record) {
64	  if (!_encryptionKey || !ENCRYPTED_STORES.has(storeName)) return record;
65	  try {
66	    const { default: Crypto } = await import('./crypto.js');
67	    const indexFields = {};
68	    if (record.id !== undefined) indexFields.id = record.id;
69	    if (storeName === 'reservations') {
70	      indexFields.userId = record.userId;
71	      indexFields.status = record.status;
72	    } else if (storeName === 'devices') {
73	      indexFields.zone = record.zone;
74	      indexFields.status = record.status;
75	    } else if (storeName === 'reports') {
76	      indexFields.type = record.type;
77	      indexFields.status = record.status;
78	    } else if (storeName === 'audit_logs') {
79	      indexFields.actor = record.actor;
80	      indexFields.timestamp = record.timestamp;
81	      indexFields.action = record.action;
82	    } else if (storeName === 'notifications') {
83	      indexFields.userId = record.userId;
84	      indexFields.read = record.read;
85	      indexFields.scheduledFor = record.scheduledFor;
86	    } else if (storeName === 'command_outbox') {
87	      indexFields.status = record.status;
88	      indexFields.deviceId = record.deviceId;
89	    } else if (storeName === 'rate_limits') {
90	      indexFields.scope = record.scope;
91	      indexFields.action = record.action;
92	    } else if (storeName === 'entry_permissions') {
93	      indexFields.reservationId = record.reservationId;
94	      indexFields.status = record.status;
95	    } else if (storeName === 'pois') {
96	      indexFields.zone = record.zone;
97	    } else if (storeName === 'content') {
98	      indexFields.status = record.status;
99	      indexFields.workflowState = record.workflowState;
100	    } else if (storeName === 'geofences') {
101	      indexFields.zone = record.zone;
102	    }
103	    const encrypted = await Crypto.encryptRecord(record, _encryptionKey);
104	    return { ...encrypted, ...indexFields };
105	  } catch {
106	    return record;
107	  }
108	}
109	
110	async function decryptIfNeeded(storeName, record) {
111	  if (!record || !record._encrypted || !_encryptionKey) return record;
112	  if (!ENCRYPTED_STORES.has(storeName)) return record;
113	  try {
114	    const { default: Crypto } = await import('./crypto.js');
115	    const decrypted = await Crypto.decryptRecord(record, _encryptionKey);
116	    decrypted.id = record.id;
117	    return decrypted;
118	  } catch {
119	    return record;
120	  }
121	}
122	
123	async function decryptArray(storeName, records) {
124	  if (!_encryptionKey || !ENCRYPTED_STORES.has(storeName)) return records;
125	  return Promise.all(records.map(r => decryptIfNeeded(storeName, r)));
126	}
127	
128	function open() {
129	  if (dbInstance) return Promise.resolve(dbInstance);
130	
131	  return new Promise((resolve, reject) => {
132	    const request = indexedDB.open(DB_NAME, DB_VERSION);
133	    request.onupgradeneeded = (event) => {
134	      const db = event.target.result;
135	      for (const [name, opts] of Object.entries(STORES)) {
136	        let store;
137	        if (!db.objectStoreNames.contains(name)) {
138	          store = db.createObjectStore(name, { keyPath: opts.keyPath, autoIncrement: opts.autoIncrement });
139	        } else {
140	          store = event.target.transaction.objectStore(name);
141	        }
142	        if (opts.indexes) {
143	          for (const idx of opts.indexes) {
144	            if (!store.indexNames.contains(idx.name)) {
145	              store.createIndex(idx.name, idx.keyPath, { unique: idx.unique || false });
146	            }
147	          }
148	        }
149	      }
150	    };
151	    request.onsuccess = (event) => {
152	      dbInstance = event.target.result;
153	      resolve(dbInstance);
154	    };
155	    request.onerror = (event) => {
156	      reject(event.target.error);
157	    };
158	  });
159	}
160	
161	async function getStore(storeName, mode = 'readonly') {
162	  const db = await open();
163	  const tx = db.transaction(storeName, mode);
164	  return tx.objectStore(storeName);
165	}
166	
167	function promisify(request) {
168	  return new Promise((resolve, reject) => {
169	    request.onsuccess = () => resolve(request.result);
170	    request.onerror = () => reject(request.error);
171	  });
172	}
173	
174	const DB = {
175	  async getAll(storeName) {
176	    const store = await getStore(storeName);
177	    const records = await promisify(store.getAll());
178	    return decryptArray(storeName, records);
179	  },
180	  async get(storeName, id) {
181	    const store = await getStore(storeName);
182	    const record = await promisify(store.get(id));
183	    return decryptIfNeeded(storeName, record);
184	  },
185	  async getByIndex(storeName, indexName, value) {
186	    const store = await getStore(storeName);
187	    const index = store.index(indexName);
188	    const records = await promisify(index.getAll(value));
189	    return decryptArray(storeName, records);
190	  },
191	  async getOneByIndex(storeName, indexName, value) {
192	    const store = await getStore(storeName);
193	    const index = store.index(indexName);
194	    const record = await promisify(index.get(value));
195	    return decryptIfNeeded(storeName, record);
196	  },
197	  async add(storeName, record) {
198	    const encrypted = await encryptIfNeeded(storeName, record);
199	    const store = await getStore(storeName, 'readwrite');
200	    return promisify(store.add(encrypted));
201	  },
202	  async put(storeName, record) {
203	    if (storeName === 'audit_logs') throw new Error('audit_logs is append-only; records cannot be modified');
204	    const encrypted = await encryptIfNeeded(storeName, record);
205	    const store = await getStore(storeName, 'readwrite');
206	    return promisify(store.put(encrypted));
207	  },
208	  async remove(storeName, id) {
209	    if (storeName === 'audit_logs') throw new Error('audit_logs is append-only; records cannot be deleted');
210	    const store = await getStore(storeName, 'readwrite');
211	    return promisify(store.delete(id));
212	  },
213	  async clear(storeName) {
214	    if (storeName === 'audit_logs') throw new Error('audit_logs is append-only; store cannot be cleared');
215	    const store = await getStore(storeName, 'readwrite');
216	    return promisify(store.clear());
217	  },
218	  async count(storeName) {
219	    const store = await getStore(storeName);
220	    return promisify(store.count());
221	  },
222	  async close() {
223	    if (dbInstance) {
224	      dbInstance.close();
225	      dbInstance = null;
226	    }
227	  }
228	};
229	
230	export { setEncryptionKey, clearEncryptionKey, getEncryptionKey };
231	export default DB;
