1	/**
2	 * Web Crypto API helpers — AES-GCM encryption with PBKDF2 key derivation.
3	 */
4	const SALT_LENGTH = 16;
5	const IV_LENGTH = 12;
6	const ITERATIONS = 100000;
7	const ENC_AT_REST_SALT = 'harborgate-at-rest-v1';
8	
9	async function deriveKey(password, salt) {
10	  const enc = new TextEncoder();
11	  const keyMaterial = await crypto.subtle.importKey(
12	    'raw',
13	    enc.encode(password),
14	    'PBKDF2',
15	    false,
16	    ['deriveKey']
17	  );
18	
19	  return crypto.subtle.deriveKey(
20	    { name: 'PBKDF2', salt, iterations: ITERATIONS, hash: 'SHA-256' },
21	    keyMaterial,
22	    { name: 'AES-GCM', length: 256 },
23	    false,
24	    ['encrypt', 'decrypt']
25	  );
26	}
27	
28	const Crypto = {
29	  async encrypt(plaintext, password) {
30	    const enc = new TextEncoder();
31	    const salt = crypto.getRandomValues(new Uint8Array(SALT_LENGTH));
32	    const iv = crypto.getRandomValues(new Uint8Array(IV_LENGTH));
33	    const key = await deriveKey(password, salt);
34	
35	    const ciphertext = await crypto.subtle.encrypt(
36	      { name: 'AES-GCM', iv },
37	      key,
38	      enc.encode(plaintext)
39	    );
40	
41	    const combined = new Uint8Array(salt.length + iv.length + ciphertext.byteLength);
42	    combined.set(salt, 0);
43	    combined.set(iv, salt.length);
44	    combined.set(new Uint8Array(ciphertext), salt.length + iv.length);
45	
46	    return btoa(String.fromCharCode(...combined));
47	  },
48	
49	  async decrypt(encoded, password) {
50	    const data = Uint8Array.from(atob(encoded), c => c.charCodeAt(0));
51	    const salt = data.slice(0, SALT_LENGTH);
52	    const iv = data.slice(SALT_LENGTH, SALT_LENGTH + IV_LENGTH);
53	    const ciphertext = data.slice(SALT_LENGTH + IV_LENGTH);
54	
55	    const key = await deriveKey(password, salt);
56	
57	    const plainBuffer = await crypto.subtle.decrypt(
58	      { name: 'AES-GCM', iv },
59	      key,
60	      ciphertext
61	    );
62	
63	    return new TextDecoder().decode(plainBuffer);
64	  },
65	
66	  generateId() {
67	    return crypto.getRandomValues(new Uint8Array(16))
68	      .reduce((s, b) => s + b.toString(16).padStart(2, '0'), '');
69	  },
70	
71	  async hashPassword(password, salt) {
72	    const enc = new TextEncoder();
73	    const saltBytes = salt ? Uint8Array.from(atob(salt), c => c.charCodeAt(0)) : crypto.getRandomValues(new Uint8Array(SALT_LENGTH));
74	    const keyMaterial = await crypto.subtle.importKey(
75	      'raw', enc.encode(password), 'PBKDF2', false, ['deriveBits']
76	    );
77	    const bits = await crypto.subtle.deriveBits(
78	      { name: 'PBKDF2', salt: saltBytes, iterations: ITERATIONS, hash: 'SHA-256' },
79	      keyMaterial,
80	      256
81	    );
82	    const hashB64 = btoa(String.fromCharCode(...new Uint8Array(bits)));
83	    const saltB64 = salt || btoa(String.fromCharCode(...saltBytes));
84	    return { hash: hashB64, salt: saltB64 };
85	  },
86	
87	  async verifyPassword(password, storedHash, storedSalt) {
88	    const { hash } = await this.hashPassword(password, storedSalt);
89	    return hash === storedHash;
90	  },
91	
92	  async encryptObject(obj, password) {
93	    const json = JSON.stringify(obj);
94	    return this.encrypt(json, password);
95	  },
96	
97	  async decryptObject(encrypted, password) {
98	    const json = await this.decrypt(encrypted, password);
99	    return JSON.parse(json);
100	  },
101	
102	  /**
103	   * Derive a Key Encryption Key (KEK) from the user's password.
104	   * Used to wrap/unwrap the shared Data Encryption Key (DEK).
105	   */
106	  async deriveKEK(password) {
107	    const enc = new TextEncoder();
108	    const salt = enc.encode(ENC_AT_REST_SALT);
109	    const keyMaterial = await crypto.subtle.importKey(
110	      'raw', enc.encode(password), 'PBKDF2', false, ['deriveKey']
111	    );
112	    return crypto.subtle.deriveKey(
113	      { name: 'PBKDF2', salt, iterations: ITERATIONS, hash: 'SHA-256' },
114	      keyMaterial,
115	      { name: 'AES-GCM', length: 256 },
116	      false,
117	      ['wrapKey', 'unwrapKey']
118	    );
119	  },
120	
121	  /**
122	   * Generate a random Data Encryption Key (DEK) for at-rest encryption.
123	   * Created once during initial setup; shared across all users via key wrapping.
124	   */
125	  async generateDEK() {
126	    return crypto.subtle.generateKey(
127	      { name: 'AES-GCM', length: 256 },
128	      true,  // extractable — required for wrapKey
129	      ['encrypt', 'decrypt']
130	    );
131	  },
132	
133	  /**
134	   * Wrap (encrypt) the DEK with a user's KEK for persistent storage.
135	   * Returns { iv, wrapped } as base64 strings.
136	   */
137	  async wrapDEK(dek, kek) {
138	    const iv = crypto.getRandomValues(new Uint8Array(IV_LENGTH));
139	    const wrapped = await crypto.subtle.wrapKey('raw', dek, kek, { name: 'AES-GCM', iv });
140	    return {
141	      iv: btoa(String.fromCharCode(...iv)),
142	      wrapped: btoa(String.fromCharCode(...new Uint8Array(wrapped)))
143	    };
144	  },
145	
146	  /**
147	   * Unwrap (decrypt) the DEK using a user's KEK.
148	   * Returns a CryptoKey suitable for encrypt/decrypt operations.
149	   */
150	  async unwrapDEK(wrappedData, kek) {
151	    const iv = Uint8Array.from(atob(wrappedData.iv), c => c.charCodeAt(0));
152	    const wrapped = Uint8Array.from(atob(wrappedData.wrapped), c => c.charCodeAt(0));
153	    return crypto.subtle.unwrapKey(
154	      'raw', wrapped, kek,
155	      { name: 'AES-GCM', iv },
156	      { name: 'AES-GCM', length: 256 },
157	      true,  // extractable — so admin can re-wrap for new users
158	      ['encrypt', 'decrypt']
159	    );
160	  },
161	
162	  /**
163	   * Encrypt a record payload with a CryptoKey (for at-rest encryption).
164	   */
165	  async encryptRecord(record, cryptoKey) {
166	    const enc = new TextEncoder();
167	    const iv = crypto.getRandomValues(new Uint8Array(IV_LENGTH));
168	    const plaintext = enc.encode(JSON.stringify(record));
169	    const ciphertext = await crypto.subtle.encrypt({ name: 'AES-GCM', iv }, cryptoKey, plaintext);
170	    const combined = new Uint8Array(iv.length + ciphertext.byteLength);
171	    combined.set(iv, 0);
172	    combined.set(new Uint8Array(ciphertext), iv.length);
173	    return {
174	      _encrypted: true,
175	      _payload: btoa(String.fromCharCode(...combined))
176	    };
177	  },
178	
179	  /**
180	   * Decrypt a record payload with a CryptoKey (for at-rest decryption).
181	   */
182	  async decryptRecord(encRecord, cryptoKey) {
183	    if (!encRecord || !encRecord._encrypted) return encRecord;
184	    const data = Uint8Array.from(atob(encRecord._payload), c => c.charCodeAt(0));
185	    const iv = data.slice(0, IV_LENGTH);
186	    const ciphertext = data.slice(IV_LENGTH);
187	    const plainBuffer = await crypto.subtle.decrypt({ name: 'AES-GCM', iv }, cryptoKey, ciphertext);
188	    return JSON.parse(new TextDecoder().decode(plainBuffer));
189	  }
190	};
191	
192	export default Crypto;
