1	import { describe, it } from 'node:test';
2	import assert from 'node:assert/strict';
3	import { webcrypto } from 'node:crypto';
4	
5	if (!globalThis.crypto) globalThis.crypto = webcrypto;
6	
7	// We test the crypto logic that's also in the production module.
8	// The production crypto.js uses browser globals (btoa/atob) so we use
9	// the Node.js crypto API directly for the same PBKDF2+AES-GCM logic.
10	
11	const SALT_LENGTH = 16;
12	const IV_LENGTH = 12;
13	const ITERATIONS = 100000;
14	
15	async function deriveKey(password, salt) {
16	  const enc = new TextEncoder();
17	  const keyMaterial = await crypto.subtle.importKey(
18	    'raw', enc.encode(password), 'PBKDF2', false, ['deriveKey']
19	  );
20	  return crypto.subtle.deriveKey(
21	    { name: 'PBKDF2', salt, iterations: ITERATIONS, hash: 'SHA-256' },
22	    keyMaterial,
23	    { name: 'AES-GCM', length: 256 },
24	    false,
25	    ['encrypt', 'decrypt']
26	  );
27	}
