29	async function encrypt(plaintext, password) {
30	  const enc = new TextEncoder();
31	  const salt = crypto.getRandomValues(new Uint8Array(SALT_LENGTH));
32	  const iv = crypto.getRandomValues(new Uint8Array(IV_LENGTH));
33	  const key = await deriveKey(password, salt);
34	  const ciphertext = await crypto.subtle.encrypt({ name: 'AES-GCM', iv }, key, enc.encode(plaintext));
35	  const combined = new Uint8Array(salt.length + iv.length + ciphertext.byteLength);
36	  combined.set(salt, 0);
37	  combined.set(iv, salt.length);
38	  combined.set(new Uint8Array(ciphertext), salt.length + iv.length);
39	  return Buffer.from(combined).toString('base64');
40	}
41	
42	async function decrypt(encoded, password) {
43	  const data = Buffer.from(encoded, 'base64');
44	  const salt = data.subarray(0, SALT_LENGTH);
45	  const iv = data.subarray(SALT_LENGTH, SALT_LENGTH + IV_LENGTH);
46	  const ciphertext = data.subarray(SALT_LENGTH + IV_LENGTH);
47	  const key = await deriveKey(password, salt);
48	  const plainBuffer = await crypto.subtle.decrypt({ name: 'AES-GCM', iv }, key, ciphertext);
49	  return new TextDecoder().decode(plainBuffer);
50	}
51	
52	function generateId() {
53	  return crypto.getRandomValues(new Uint8Array(16))
54	    .reduce((s, b) => s + b.toString(16).padStart(2, '0'), '');
55	}
