57	describe('Crypto — AES-GCM + PBKDF2', () => {
58	  it('should encrypt and decrypt a string', async () => {
59	    const message = 'Hello HarborGate';
60	    const password = 'test-password-123';
61	    const encrypted = await encrypt(message, password);
62	    assert.notEqual(encrypted, message);
63	    const decrypted = await decrypt(encrypted, password);
64	    assert.equal(decrypted, message);
65	  });
66	
67	  it('should fail decryption with wrong password', async () => {
68	    const encrypted = await encrypt('secret', 'right-password');
69	    await assert.rejects(
70	      () => decrypt(encrypted, 'wrong-password'),
71	      (err) => err instanceof Error
72	    );
73	  });
74	
75	  it('should produce different ciphertexts for same input', async () => {
76	    const a = await encrypt('same message', 'password');
77	    const b = await encrypt('same message', 'password');
78	    assert.notEqual(a, b);
79	  });
80	
81	  it('should generate unique IDs', () => {
