107	describe('Crypto — At-Rest Encryption', () => {
108	  async function deriveSessionKey(password) {
109	    const enc = new TextEncoder();
110	    const salt = enc.encode('harborgate-at-rest-v1');
111	    const keyMaterial = await crypto.subtle.importKey(
112	      'raw', enc.encode(password), 'PBKDF2', false, ['deriveKey']
113	    );
114	    return crypto.subtle.deriveKey(
115	      { name: 'PBKDF2', salt, iterations: ITERATIONS, hash: 'SHA-256' },
116	      keyMaterial,
117	      { name: 'AES-GCM', length: 256 },
118	      false,
119	      ['encrypt', 'decrypt']
120	    );
121	  }
122	
123	  async function encryptRecord(record, key) {
124	    const enc = new TextEncoder();
125	    const iv = crypto.getRandomValues(new Uint8Array(IV_LENGTH));
126	    const plaintext = enc.encode(JSON.stringify(record));
127	    const ciphertext = await crypto.subtle.encrypt({ name: 'AES-GCM', iv }, key, plaintext);
128	    const combined = new Uint8Array(iv.length + ciphertext.byteLength);
129	    combined.set(iv, 0);
130	    combined.set(new Uint8Array(ciphertext), iv.length);
131	    return { _encrypted: true, _payload: Buffer.from(combined).toString('base64') };
132	  }
