193	describe('Password Hashing (PBKDF2)', () => {
194	  // Import Crypto for hashing tests — uses Web Crypto which is available in Node
195	  const SALT_LENGTH = 16;
196	  const ITERATIONS = 100000;
197	
198	  async function hashPassword(password, salt) {
199	    const enc = new TextEncoder();
200	    const saltBytes = salt ? Uint8Array.from(atob(salt), c => c.charCodeAt(0)) : crypto.getRandomValues(new Uint8Array(SALT_LENGTH));
201	    const keyMaterial = await crypto.subtle.importKey('raw', enc.encode(password), 'PBKDF2', false, ['deriveBits']);
202	    const bits = await crypto.subtle.deriveBits(
203	      { name: 'PBKDF2', salt: saltBytes, iterations: ITERATIONS, hash: 'SHA-256' },
204	      keyMaterial, 256
205	    );
206	    const hashB64 = Buffer.from(new Uint8Array(bits)).toString('base64');
207	    const saltB64 = salt || Buffer.from(saltBytes).toString('base64');
208	    return { hash: hashB64, salt: saltB64 };
209	  }
210	
211	  async function verifyPassword(password, storedHash, storedSalt) {
212	    const { hash } = await hashPassword(password, storedSalt);
213	    return hash === storedHash;
214	  }
215	
216	  it('should hash and verify a password', async () => {
217	    const { hash, salt } = await hashPassword('TestPassword1!');
218	    const valid = await verifyPassword('TestPassword1!', hash, salt);
219	    assert.equal(valid, true);
220	  });
221	
222	  it('should fail verification with wrong password', async () => {
223	    const { hash, salt } = await hashPassword('TestPassword1!');
224	    const valid = await verifyPassword('WrongPassword1!', hash, salt);
225	    assert.equal(valid, false);
226	  });
