1	/**
2	 * Pure authentication logic — no browser/DB dependencies.
3	 */
4	
5	export const MAX_ATTEMPTS = 5;
6	export const LOCKOUT_DURATION = 15 * 60 * 1000;      // 15 minutes
7	export const SESSION_TIMEOUT = 30 * 60 * 1000;       // 30 minutes
8	export const SESSION_WARNING = 25 * 60 * 1000;       // 25 minutes
9	
10	export const PASSWORD_RULES = [
11	  { test: (p) => p.length >= 12, msg: 'Minimum 12 characters' },
12	  { test: (p) => /[A-Z]/.test(p), msg: 'At least 1 uppercase letter' },
13	  { test: (p) => /[a-z]/.test(p), msg: 'At least 1 lowercase letter' },
14	  { test: (p) => /[0-9]/.test(p), msg: 'At least 1 number' },
15	  { test: (p) => /[^A-Za-z0-9]/.test(p), msg: 'At least 1 symbol' }
16	];
17	
18	export function validatePassword(password) {
19	  const failures = PASSWORD_RULES.filter(r => !r.test(password));
20	  return { valid: failures.length === 0, errors: failures.map(f => f.msg) };
21	}
22	
23	export function isAccountLocked(user, now = Date.now()) {
24	  if (!user.lockedUntil) return false;
25	  return now < user.lockedUntil;
26	}
27	
28	export function processFailedLogin(user, now = Date.now()) {
29	  user.failedAttempts = (user.failedAttempts || 0) + 1;
30	  if (user.failedAttempts >= MAX_ATTEMPTS) {
31	    user.lockedUntil = now + LOCKOUT_DURATION;
32	    user.failedAttempts = 0;
33	    return { locked: true };
34	  }
35	  return { locked: false, attemptsLeft: MAX_ATTEMPTS - user.failedAttempts };
36	}
37	
38	export function processSuccessfulLogin(user) {
39	  user.failedAttempts = 0;
40	  user.lockedUntil = null;
41	  user.lastLogin = Date.now();
42	}
43	
44	export function isSessionExpired(session, now = Date.now()) {
45	  return now - session.lastActivity > SESSION_TIMEOUT;
46	}
47	
48	export function isSessionWarningDue(session, now = Date.now()) {
49	  return now - session.lastActivity > SESSION_WARNING;
50	}
51	
52	export const ROLE_DEFINITIONS = [
53	  { name: 'visitor', label: 'Regular User', permissions: ['reservations.view', 'reservations.create', 'map.view', 'notifications.view'] },
54	  { name: 'operator', label: 'Merchant/Operator', permissions: ['reservations.view', 'reservations.create', 'reservations.manage', 'map.view', 'notifications.view', 'devices.unlock', 'devices.view'] },
55	  { name: 'reviewer', label: 'Reviewer', permissions: ['content.view', 'content.review', 'content.moderate', 'notifications.view', 'map.view'] },
56	  { name: 'admin', label: 'Administrator', permissions: ['*'] }
57	];
58	
59	export function hasPermissionForRole(roleName, permission) {
60	  if (roleName === 'admin') return true;
61	  const role = ROLE_DEFINITIONS.find(r => r.name === roleName);
62	  if (!role) return false;
63	  return role.permissions.includes(permission) || role.permissions.includes('*');
64	}
