1	/**
2	 * Pure notification logic — no browser/DB dependencies.
3	 */
4	
5	export const MAX_RETRIES = 3;
6	
7	export const TEMPLATES = {
8	  reservation_approved: 'Your reservation {reservationId} has been approved.',
9	  reservation_denied: 'Your reservation {reservationId} has been denied.',
10	  reservation_reminder_24h: 'Reminder: Your reservation {reservationId} at {zone} is in 24 hours.',
11	  reservation_reminder_1h: 'Reminder: Your reservation {reservationId} at {zone} is in 1 hour.',
12	  unlock_success: 'Door "{doorName}" has been unlocked successfully.',
13	  unlock_failed: 'Failed to unlock door "{doorName}". Please try again.',
14	  content_flagged: 'Content "{contentTitle}" has been flagged for review.',
15	  content_published: 'Content "{contentTitle}" has been published.',
16	  overdue_item: 'Overdue: {itemDescription} requires attention.',
17	  missing_materials: 'Missing materials for reservation {reservationId}: {details}.',
18	  account_locked: 'Your account has been locked due to multiple failed login attempts.',
19	  user_banned: 'Account "{username}" has been banned. Reason: {reason}'
20	};
21	
22	export function resolveTemplate(templateId, variables = {}) {
23	  let template = TEMPLATES[templateId];
24	  if (!template) return templateId;
25	
26	  for (const [key, value] of Object.entries(variables)) {
27	    template = template.replace(new RegExp(`\\{${key}\\}`, 'g'), value);
28	  }
29	  return template;
30	}
31	
32	export function createNotificationObject({ userId, templateId, variables, type = 'info', scheduledFor = null }) {
33	  const message = resolveTemplate(templateId, variables);
34	  return {
35	    userId,
36	    templateId,
37	    variables,
38	    message,
39	    type,
40	    read: false,
41	    status: 'pending',
42	    retryCount: 0,
43	    scheduledFor: scheduledFor || Date.now(),
44	    createdAt: Date.now(),
45	    deliveredAt: null,
46	    failedAt: null
47	  };
48	}
49	
50	export function applyDelivery(notif) {
51	  notif.status = 'delivered';
52	  notif.deliveredAt = Date.now();
53	  return notif;
54	}
55	
56	export function applyFailedDelivery(notif) {
57	  notif.retryCount += 1;
58	  if (notif.retryCount >= MAX_RETRIES) {
59	    notif.status = 'failed';
60	    notif.failedAt = Date.now();
61	  }
62	  return notif;
63	}
