1	/**
2	 * Lightweight client-side state store with subscription support.
3	 * Coordinates views, modals, drawers, table pagination/sorting.
4	 */
5	const Store = {
6	  _state: {},
7	  _listeners: [],
8	
9	  get(key) {
10	    return this._state[key];
11	  },
12	
13	  set(key, value) {
14	    this._state[key] = value;
15	    this._notify(key, value);
16	  },
17	
18	  getAll() {
19	    return { ...this._state };
20	  },
21	
22	  subscribe(listener) {
23	    this._listeners.push(listener);
24	    return () => {
25	      this._listeners = this._listeners.filter(l => l !== listener);
26	    };
27	  },
28	
29	  _notify(key, value) {
30	    for (const listener of this._listeners) {
31	      listener(key, value);
32	    }
33	  },
34	
35	  reset() {
36	    this._state = {};
37	    this._listeners = [];
38	  },
39	
40	  // Table pagination/sorting helpers
41	  initTable(tableId, data, opts = {}) {
42	    const config = {
43	      page: 1,
44	      pageSize: opts.pageSize || 10,
45	      sortKey: opts.sortKey || null,
46	      sortDir: opts.sortDir || 'asc',
47	      data: data,
48	      filtered: data
49	    };
50	    this.set(`table_${tableId}`, config);
51	    return config;
52	  },
53	
54	  getTablePage(tableId) {
55	    const config = this.get(`table_${tableId}`);
56	    if (!config) return { rows: [], page: 1, totalPages: 1 };
57	
58	    let sorted = [...config.filtered];
59	    if (config.sortKey) {
60	      sorted.sort((a, b) => {
61	        const av = a[config.sortKey] ?? '';
62	        const bv = b[config.sortKey] ?? '';
63	        const cmp = typeof av === 'number' ? av - bv : String(av).localeCompare(String(bv));
64	        return config.sortDir === 'asc' ? cmp : -cmp;
65	      });
66	    }
67	
68	    const totalPages = Math.max(1, Math.ceil(sorted.length / config.pageSize));
69	    const page = Math.min(config.page, totalPages);
70	    const start = (page - 1) * config.pageSize;
71	    const rows = sorted.slice(start, start + config.pageSize);
72	
73	    return { rows, page, totalPages, total: sorted.length };
74	  },
75	
76	  setTablePage(tableId, page) {
77	    const config = this.get(`table_${tableId}`);
78	    if (config) {
79	      config.page = page;
80	      this.set(`table_${tableId}`, config);
81	    }
82	  },
83	
84	  setTableSort(tableId, key) {
85	    const config = this.get(`table_${tableId}`);
86	    if (config) {
87	      if (config.sortKey === key) {
88	        config.sortDir = config.sortDir === 'asc' ? 'desc' : 'asc';
89	      } else {
90	        config.sortKey = key;
91	        config.sortDir = 'asc';
92	      }
93	      config.page = 1;
94	      this.set(`table_${tableId}`, config);
95	    }
96	  },
97	
98	  setTableFilter(tableId, filterFn) {
99	    const config = this.get(`table_${tableId}`);
100	    if (config) {
101	      config.filtered = filterFn ? config.data.filter(filterFn) : config.data;
102	      config.page = 1;
103	      this.set(`table_${tableId}`, config);
104	    }
105	  }
106	};
107	
108	export default Store;
