127	async function login(username, password) {
128	  const [userRl, globalRl] = await Promise.all([
129	    checkRateLimit('user', username, 'user_login'),
130	    checkRateLimit('global', '', 'user_login')
131	  ]);
132	  if (!userRl.allowed || !globalRl.allowed) {
133	    await addAuditLog('login_rate_limited', username, { remaining: Math.min(userRl.remaining, globalRl.remaining) });
134	    return { success: false, error: 'Too many login attempts. Please try again later.' };
135	  }
136	
137	  const user = await DB.getOneByIndex('users', 'username', username);
138	  if (!user) return { success: false, error: 'Invalid credentials' };
139	  if (user.banned) return { success: false, error: 'Account is banned' };
140	  if (isAccountLocked(user)) {
141	    const remaining = Math.ceil((user.lockedUntil - Date.now()) / 60000);
142	    return { success: false, error: `Account locked. Try again in ${remaining} minute(s).` };
143	  }
144	
145	  const valid = await Crypto.verifyPassword(password, user.passwordHash, user.passwordSalt);
146	  if (!valid) {
147	    const result = processFailedLogin(user);
148	    await DB.put('users', user);
149	    if (result.locked) {
150	      await addAuditLog('account_locked', username, { reason: 'max_failed_attempts' });
151	      return { success: false, error: 'Account locked for 15 minutes due to too many failed attempts.' };
152	    }
153	    return { success: false, error: 'Invalid credentials', attemptsLeft: result.attemptsLeft };
154	  }
155	
156	  processSuccessfulLogin(user);
157	  await DB.put('users', user);
158	
159	  // Unwrap the shared Data Encryption Key (DEK) using password-derived KEK
160	  const kek = await Crypto.deriveKEK(password);
161	  const wrappedKeys = getWrappedKeys();
162	  const userWrapped = wrappedKeys[username];
163	  if (userWrapped) {
164	    const dek = await Crypto.unwrapDEK(userWrapped, kek);
165	    setEncryptionKey(dek);
166	  }
167	
168	  const token = Crypto.generateId();
169	  const session = {
170	    token,
171	    userId: user.id,
172	    username: user.username,
173	    role: user.role,
174	    createdAt: Date.now(),
175	    lastActivity: Date.now()
176	  };
177	
178	  localStorage.setItem(SESSION_KEY, JSON.stringify(session));
179	  Store.set('session', session);
180	  Store.set('currentUser', { id: user.id, username: user.username, role: user.role });
181	
182	  startIdleTimer();
183	  await addAuditLog('user_login', username, { userId: user.id });
184	  return { success: true, session };
185	}
