42	export async function consumeEntry(permissionId, actor = null) {
43	  const perm = await DB.get('entry_permissions', permissionId);
44	  if (!perm) return { success: false, error: 'Permission not found' };
45	
46	  // Object-level authorization: only the permission owner, admin, or operator may consume
47	  if (actor) {
48	    const isOwner = perm.userId === actor.id;
49	    const isPrivileged = actor.role === 'admin' || actor.role === 'operator';
50	    if (!isOwner && !isPrivileged) {
51	      return { success: false, error: 'Not authorized to consume this entry permission' };
52	    }
53	  }
54	
55	  const before = { ...perm };
56	  const result = _consumeEntry(perm);
57	  if (!result.success) return result;
58	
59	  await DB.put('entry_permissions', perm);
60	  await addAuditLog('entry_consumed', actor?.username || null, {
61	    permissionId: perm.id,
62	    usedEntries: perm.usedEntries,
63	    maxEntries: perm.maxEntries
64	  }, before, perm);
65	
66	  return { success: true, permission: perm };
67	}
