86	 * Get all entry permissions for a reservation.
87	 * If actor is provided, verifies the actor owns the reservation or is privileged.
88	 * Returns [] (not an error) for unauthorized access to avoid leaking existence.
89	 */
90	export async function getPermissionsForReservation(reservationId, actor = null) {
91	  // Enforce actor for authorization check — callers must pass the current user
92	  if (!actor) return [];
93	  const reservation = await DB.get('reservations', reservationId);
94	  // If reservation not found, return empty to prevent orphaned permission enumeration
95	  if (!reservation) return [];
96	  const isOwner = reservation.userId === actor.id;
97	  const isPrivileged = actor.role === 'admin' || actor.role === 'operator';
98	  if (!isOwner && !isPrivileged) return [];
99	  return DB.getByIndex('entry_permissions', 'reservationId', reservationId);
100	}
