21	export async function createNotification({ userId, templateId, variables, type = 'info', scheduledFor = null }) {
22	  const notification = createNotificationObject({ userId, templateId, variables, type, scheduledFor });
23	
24	  const id = await DB.add('notifications', notification);
25	  notification.id = id;
26	
27	  // Attempt immediate delivery if not scheduled in future
28	  if (!scheduledFor || scheduledFor <= Date.now()) {
29	    return deliverNotification(notification);
30	  }
31	
32	  return notification;
