63	export async function processScheduledNotifications() {
64	  const all = await DB.getAll('notifications');
65	  const now = Date.now();
66	  const due = all.filter(n => n.status === 'pending' && n.scheduledFor && n.scheduledFor <= now);
67	
68	  for (const n of due) {
69	    await deliverNotification(n);
70	  }
71	
72	  return due.length;
73	}
