134	   * Wrap (encrypt) the DEK with a user's KEK for persistent storage.
135	   * Returns { iv, wrapped } as base64 strings.
136	   */
137	  async wrapDEK(dek, kek) {
138	    const iv = crypto.getRandomValues(new Uint8Array(IV_LENGTH));
139	    const wrapped = await crypto.subtle.wrapKey('raw', dek, kek, { name: 'AES-GCM', iv });
140	    return {
141	      iv: btoa(String.fromCharCode(...iv)),
142	      wrapped: btoa(String.fromCharCode(...new Uint8Array(wrapped)))
143	    };
144	  },
145	
146	  /**
147	   * Unwrap (decrypt) the DEK using a user's KEK.
148	   * Returns a CryptoKey suitable for encrypt/decrypt operations.
149	   */
150	  async unwrapDEK(wrappedData, kek) {
151	    const iv = Uint8Array.from(atob(wrappedData.iv), c => c.charCodeAt(0));
152	    const wrapped = Uint8Array.from(atob(wrappedData.wrapped), c => c.charCodeAt(0));
153	    return crypto.subtle.unwrapKey(
154	      'raw', wrapped, kek,
155	      { name: 'AES-GCM', iv },
156	      { name: 'AES-GCM', length: 256 },
157	      true,  // extractable — so admin can re-wrap for new users
158	      ['encrypt', 'decrypt']
159	    );
160	  },
161	
162	  /**
163	   * Encrypt a record payload with a CryptoKey (for at-rest encryption).
164	   */
165	  async encryptRecord(record, cryptoKey) {
166	    const enc = new TextEncoder();
167	    const iv = crypto.getRandomValues(new Uint8Array(IV_LENGTH));
168	    const plaintext = enc.encode(JSON.stringify(record));
169	    const ciphertext = await crypto.subtle.encrypt({ name: 'AES-GCM', iv }, cryptoKey, plaintext);
170	    const combined = new Uint8Array(iv.length + ciphertext.byteLength);
171	    combined.set(iv, 0);
172	    combined.set(new Uint8Array(ciphertext), iv.length);
173	    return {
174	      _encrypted: true,
175	      _payload: btoa(String.fromCharCode(...combined))
176	    };
177	  },
178	
179	  /**
180	   * Decrypt a record payload with a CryptoKey (for at-rest decryption).
181	   */
182	  async decryptRecord(encRecord, cryptoKey) {
183	    if (!encRecord || !encRecord._encrypted) return encRecord;
184	    const data = Uint8Array.from(atob(encRecord._payload), c => c.charCodeAt(0));
185	    const iv = data.slice(0, IV_LENGTH);
186	    const ciphertext = data.slice(IV_LENGTH);
187	    const plainBuffer = await crypto.subtle.decrypt({ name: 'AES-GCM', iv }, cryptoKey, ciphertext);
188	    return JSON.parse(new TextDecoder().decode(plainBuffer));
189	  }
190	};
