69	export async function expirePermissions() {
70	  const all = await DB.getAll('entry_permissions');
71	  const now = Date.now();
72	  let expired = 0;
73	
74	  for (const perm of all) {
75	    if (perm.status === 'active' && now > perm.windowEnd) {
76	      perm.status = 'expired';
77	      await DB.put('entry_permissions', perm);
78	      expired++;
79	    }
80	  }
81	
82	  return expired;
