1	/**
2	 * Pure entry-permission logic — no browser/DB dependencies.
3	 */
4	
5	export const WINDOW_BEFORE_MS = 15 * 60 * 1000; // 15 min before
6	export const WINDOW_AFTER_MS = 30 * 60 * 1000;  // 30 min after
7	
8	export function calculatePermissionWindow(reservationStartTime) {
9	  const start = new Date(reservationStartTime).getTime();
10	  return {
11	    windowStart: start - WINDOW_BEFORE_MS,
12	    windowEnd: start + WINDOW_AFTER_MS
13	  };
14	}
15	
16	export function isWithinPermissionWindow(permission, now = Date.now()) {
17	  return now >= permission.windowStart && now <= permission.windowEnd;
18	}
19	
20	export function createPermissionObject(startTime, policy = 'single-use') {
21	  const { windowStart, windowEnd } = calculatePermissionWindow(startTime);
22	  return {
23	    policy,
24	    maxEntries: policy === 'single-use' ? 1 : 5,
25	    usedEntries: 0,
26	    windowStart,
27	    windowEnd,
28	    status: 'active'
29	  };
30	}
31	
32	export function consumeEntry(perm, now = Date.now()) {
33	  if (perm.status === 'consumed') return { success: false, error: 'Permission already fully consumed' };
34	  if (perm.status === 'expired') return { success: false, error: 'Permission has expired' };
35	  if (!isWithinPermissionWindow(perm, now)) return { success: false, error: 'Outside permission time window' };
36	
37	  perm.usedEntries += 1;
38	  if (perm.usedEntries >= perm.maxEntries) {
39	    perm.status = 'consumed';
40	  }
41	  return { success: true, permission: perm };
42	}
43	
44	export function getPermissionStatusLabel(perm, now = Date.now()) {
45	  if (perm.status === 'consumed') return 'Consumed';
46	  if (perm.status === 'expired') return 'Expired';
47	  if (isWithinPermissionWindow(perm, now)) return 'Active';
48	  if (now < perm.windowStart) return 'Pending';
49	  return 'Expired';
50	}
